INSERT INTO lessons (
INSERT INTO lesson_curriculum (lesson_curriculum_id, lesson_id, title, summary, sort_order) VALUES
    (1, 1, '핸드드립 기본 이해', '드리퍼, 필터, 서버, 저울 사용법과 추출 흐름을 익힙니다.', 1),
    (2, 1, 'V60 기본 레시피 실습', '15g 원두와 240g 물 기준으로 블룸과 분할 주입을 실습합니다.', 2),
    (3, 1, '맛 피드백과 조정법', '쓴맛, 산미, 밍밍함이 나타날 때 조정 방향을 정리합니다.', 3),
    (4, 2, '칼리타 구조 이해', '평평한 바닥 구조가 추출 안정성에 주는 영향을 배웁니다.', 1),
    (5, 2, '단맛 중심 레시피 실습', '물줄기, 분쇄도, 총 추출 시간을 맞춰 밸런스를 잡습니다.', 2),
    (6, 2, '재현 가능한 기록법', '레시피를 기록하고 다음 추출에서 수정하는 방법을 익힙니다.', 3),
    (7, 3, '커핑 세팅과 평가 기준', '향, 산미, 단맛, 바디, 후미를 같은 기준으로 평가합니다.', 1),
    (8, 3, '향미 노트 구분 훈련', '과일, 플로럴, 초콜릿, 견과류 계열 노트를 비교합니다.', 2),
    (9, 3, '취향 프로필 정리', '좋아하는 노트와 피해야 할 노트를 정리합니다.', 3),
    (10, 4, '산지와 가공 방식 이해', '워시드, 내추럴, 허니, 무산소 발효의 차이를 배웁니다.', 1),
    (11, 4, '로스팅 레벨 비교', '라이트, 미디엄, 다크 로스팅의 향미 차이를 비교합니다.', 2),
    (12, 4, '나에게 맞는 원두 고르기', '취향 설문 기준으로 구매 후보를 좁히는 방법을 실습합니다.', 3),
    (13, 5, '실기 시험 흐름 파악', '준비, 추출, 정리까지 시험 루틴을 단계별로 익힙니다.', 1),
    (14, 5, '기본 동작 반복 실습', '시간 안에 안정적으로 수행하는 손동작을 연습합니다.', 2),
    (15, 5, '감점 요소 점검', '위생, 순서, 시간 관리에서 자주 발생하는 실수를 확인합니다.', 3),
    (16, 6, '시험 루틴 압축 훈련', '제한 시간 안에 일관된 결과를 내는 루틴을 만듭니다.', 1),
    (17, 6, '모의 실기 테스트', '실제 시험처럼 전체 과정을 반복하고 피드백을 받습니다.', 2),
    (18, 6, '개인 약점 보완', '개인별로 부족한 동작과 시간 관리 포인트를 교정합니다.', 3),
    (19, 7, '홈카페 장비 세팅', '집에서 쓰기 좋은 기본 장비와 관리법을 익힙니다.', 1),
    (20, 7, '데일리 레시피 만들기', '매일 재현 가능한 간단한 핸드드립 레시피를 실습합니다.', 2),
    (21, 7, '원두 보관과 분쇄 관리', '맛을 오래 유지하는 보관법과 분쇄도 관리법을 배웁니다.', 3),
    (22, 8, '추출 변수 구조화', '분쇄도, 온도, 비율, 시간의 상관관계를 정리합니다.', 1),
    (23, 8, '목표 맛별 레시피 튜닝', '과일향 강조와 바디 강조 레시피를 비교 실습합니다.', 2),
    (24, 8, '개인 레시피 설계', '본인 취향에 맞는 최종 레시피를 설계하고 기록합니다.', 3)
